using System;
using System.Collections.Generic;
using System.IdentityModel.Tokens.Saml2;
using System.Security.Cryptography;
using System.Text;
using System.Xml;
using System.Xml.Linq;

public class SAMLRequestGenerator
{
    private const string NameIdPolicyFormat = "urn:oasis:names:tc:SAML:2.0:nameid-format:transient";
    private const string EncryptionAlgorithm = "DES_EDE3";
    private const string SignatureAlgorithm = "http://www.w3.org/2001/04/xmldsig-more#rsa-sha1";

    public XElement GenerateRequest(string entityId, string nameId, string audienceUri)
    {
        var request = new Saml2AuthenticationRequest
        {
            NameIdentifierPolicy = new NameIdentifierPolicyType() { Format = NameIdPolicyFormat },
            Destination = audienceUri,
            Issuer = entityId,
            NameID = nameId,
            ProtocolBinding = "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
        };

        var xmlDoc = new XmlDocument();
        request.WriteXml(xmlDoc);

        SignAndEncrypt(xmlDoc, entityId, audienceUri);

        return xmlDoc.DocumentElement;
    }

    private void SignAndEncrypt(XmlDocument xmlDoc, string entityId, string audienceUri)
    {
        var rsa = GetRSAKey();
        var encryptedAttributes = EncryptAttributes(xmlDoc, rsa);

        var samlSignature = new XmlElement("ds:Signature", xmlDoc.DocumentElement.NamespaceManager);
        AddTransforms(samlSignature);
        AddDigitalSignatureParameters(samlSignature, rsa, audienceUri);
        AddSignedInfo(samlSignature, entityId, audienceUri, encryptedAttributes);
        AddKeyInfo(samlSignature, rsa);
        AddSignatureValue(samlSignature, rsa);

        xmlDoc.DocumentElement.AppendChild(samlSignature);
    }

    private void AddTransforms(XmlElement samlSignature)
    {
        var transforms = new XmlElement("ds:Transforms", samlSignature.NamespaceManager);
        transforms.AppendChild(new XmlElement("ds:Transform", "http://www.w3.org/2000/09/xmldsig#enveloped-signature"));
        transforms.AppendChild(new XmlElement("ds:Transform", "http://www.w3.org/2001/04/xmldsig-more#rsa-1_5"));
        samlSignature.AppendChild(transforms);
    }

    private void AddDigitalSignatureParameters(XmlElement samlSignature, RSA rsa, string audienceUri)
    {
        var parameters = new XmlElement("ds:Reference", samlSignature.NamespaceManager);
        parameters.SetAttribute("URI", "#" + samlSignature.Name);
        parameters.SetAttribute("Type", "http://www.w3.org/2001/04/xmldsig-more#SAMLAssertion");
        parameters.SetAttribute("DigestMethod", "http://www.w3.org/2000/09/xmldsig#sha1");
        parameters.AppendChild(new XmlElement("ds:DigestValue", GetSHA1Hash(xmlDoc)));
        samlSignature.AppendChild(parameters);
    }

    private void AddSignedInfo(XmlElement samlSignature, string entityId, string audienceUri, XElement encryptedAttributes)
    {
        var signedInfo = new XmlElement("ds:SignedInfo", samlSignature.NamespaceManager);
        signedInfo.AppendChild(new XmlElement("ds:CanonicalizationMethod", "http://www.w3.org/2001/10/xml-exc-c14n#"));
        signedInfo.AppendChild(new XmlElement("ds:SignatureMethod", SignatureAlgorithm));
        signedInfo.AppendChild(new XmlElement("ds:Reference", "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-saml-assertion-module-v1.1.xsd#Assertion"));
        signedInfo.AppendChild(new XmlElement("ds:Transforms", samlSignature.NamespaceManager));
        signedInfo.AppendChild(encryptedAttributes);
        samlSignature.AppendChild(signedInfo);
    }

    private void AddKeyInfo(XmlElement samlSignature, RSA rsa)
    {
        var keyInfo = new XmlElement("ds:KeyInfo", samlSignature.NamespaceManager);
        var x509Data = new XmlElement("ds:X509Data", samlSignature.NamespaceManager);
        var certificate = new XmlElement("ds:X509Certificate", samlSignature.NamespaceManager);
        certificate.InnerText = rsa.ExportX509Certificate(true).Replace("\r\n", "");
        x509Data.AppendChild(certificate);
        keyInfo.AppendChild(x509Data);
        samlSignature.AppendChild(keyInfo);
    }

    private void AddSignatureValue(XmlElement samlSignature, RSA rsa)
    {
        var signature = new XmlElement("ds:SignatureValue", samlSignature.NamespaceManager);
        signature.InnerText = Convert.ToBase64String(rsa.SignSHA1(GetSHA1Hash(xmlDoc), "RSAPKCS1"));
        samlSignature.AppendChild(signature);
    }

    private XElement EncryptAttributes(XmlDocument xmlDoc, RSA rsa)
    {
        var encryptedAttributes = new XmlElement("ds:EncryptedData", xmlDoc.DocumentElement.NamespaceManager);
        encryptedAttributes.SetAttribute("Type", "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-saml-assertion-module-v1.1.xsd#EncryptedAssertion");
        encryptedAttributes.SetAttribute("xmlns:ds", "http://www.w3.org/2000/09/xmldsig#");
        encryptedAttributes.SetAttribute("Id", Guid.NewGuid().ToString());

        var encryptionMethod = new XmlElement("ds:EncryptionMethod", encryptedAttributes.NamespaceManager);
        encryptionMethod.InnerText = EncryptionAlgorithm;
        encryptedAttributes.AppendChild(encryptionMethod);

        var keyInfo = new XmlElement("ds:KeyInfo", encryptedAttributes.NamespaceManager);
        AddKeyInfo(encryptedAttributes, rsa);
        encryptedAttributes.AppendChild(keyInfo);

        var cipherValue = new XmlElement("ds:CipherData", encryptedAttributes.NamespaceManager);
        cipherValue.SetAttribute("Type", "http://www.w3.org/2001/04/xmlenc#Element");

        using (var ms = new MemoryStream())
        {
            var writer = new XmlTextWriter(ms, Encoding.UTF8);
            xmlDoc.WriteContentTo(writer);
            writer.Flush();
            ms.Position = 0;

            using (var reader = new XmlTextReader(ms))
            {
                var encryptedXml = new XElement("EncryptedData", reader);
                cipherValue.AppendChild(encryptedXml);
            }
        }

        encryptedAttributes.AppendChild(cipherValue);
        return encryptedAttributes;
    }

    private RSA GetRSAKey()
    {
        var rsa = new RSA();
        using (var keyContainer = new RSACryptoServiceProvider(2048))
        {
            rsa.ImportParameters(keyContainer.ExportParameters(true));
        }
        return rsa;
    }

    private byte[] GetSHA1Hash(string input)
    {
        using (var sha1 = SHA1.Create())
        {
            var bytes = Encoding.UTF8.GetBytes(input);
            return sha1.ComputeHash(bytes);
        }
    }
